previewCss:
.darma-loader-uiverse-soft-equalizer {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      height: 46px;
    }
    .darma-loader-uiverse-soft-equalizer i {
      display: block;
      width: 6px;
      height: 46px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color), var(--loader-secondary-color));
      transform-origin: center bottom;
      animation: darma-loader-uiverse-soft-equalizer-barPulse 0.85s ease-in-out infinite;
    }
    .darma-loader-uiverse-soft-equalizer i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-soft-equalizer i:nth-child(2) { animation-delay: 0.09s; }
.darma-loader-uiverse-soft-equalizer i:nth-child(3) { animation-delay: 0.18s; }
.darma-loader-uiverse-soft-equalizer i:nth-child(4) { animation-delay: 0.27s; }
.darma-loader-uiverse-soft-equalizer i:nth-child(5) { animation-delay: 0.36s; }
.darma-loader-uiverse-soft-equalizer i:nth-child(6) { animation-delay: 0.45s; }
    @keyframes darma-loader-uiverse-soft-equalizer-barPulse { 0%, 100% { transform: translateY(0) scaleY(.55); opacity: .45; } 50% { transform: translateY(-7px) scaleY(1); opacity: 1; } }

